import{_ as n,o as t,c as a,a3 as r}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse(`{"title":"3. Definitions And Interpretation","description":"","frontmatter":{"title":"3. Definitions And Interpretation","eba":"Children's Services Award 2010","topics":["wages","superannuation","employment","union-matters","delegates","preliminary"]},"headers":[],"relativePath":"ebas/childrens-services/application-operation/3-definitions-and-interpretation.md","filePath":"ebas/childrens-services/application-operation/3-definitions-and-interpretation.md"}`),o={name:"ebas/childrens-services/application-operation/3-definitions-and-interpretation.md"};function s(i,e,h,l,c,p){return t(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="_3-definitions-and-interpretation" tabindex="-1">3. Definitions And Interpretation <a class="header-anchor" href="#_3-definitions-and-interpretation" aria-label="Permalink to &quot;3. Definitions And Interpretation&quot;">​</a></h1><ol><li>In this award, unless the contrary intention appears:</li></ol><p><strong>Act</strong> means the <em>Fair Work Act 2009</em> (Cth)</p><p><strong>adjunct care</strong> means care provided within a facility where the parent or guardian remains responsible for the child and remains close by, usually on the premises</p><p><strong>adult apprentice</strong> means an apprentice who is 21 years of age or over at the commencement of their apprenticeship</p><p><strong>agreement-based transitional instrument</strong> has the meaning in the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>AQF</strong> means the Australian Qualifications Framework</p><p><strong>award-based transitional instrument</strong> has the meaning in the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>casual employee</strong> has the meaning given by section 15A of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p>NOTE: Section 15A of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a> was amended with effect from 26 August 2024. Under clause 102(3) of Schedule 1 to the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>, an existing employee who was a casual employee of an employer under section 15A as it was immediately before that date is taken to be a casual employee of the employer for the purposes of section 15A after that date.</p><p><strong>childcare</strong> means a program providing care, support supervision and development for children</p><p><strong>children&#39;s services and early childhood education industry</strong> means the industry of long day care, occasional care (including those occasional care services not licensed), nurseries, childcare centres, day care facilities, family based childcare, out-of-school hours care, vacation care, adjunct care, in-home care, kindergartens and preschools, mobile centres and early childhood intervention programs</p><p><strong>default</strong> <strong>fund employee</strong> means an employee who has no chosen fund within the meaning of the <em>Superannuation Guarantee (Administration) Act 1992</em> (Cth)</p><p><strong>defined benefit member</strong> has the meaning given by the <em>Superannuation Guarantee (Administration) Act 1992</em> (Cth)</p><p><strong>Division 2B State award</strong> has the meaning in Schedule 3A of the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>Division 2B State employment agreement</strong> has the meaning in Schedule 3A of the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>employee</strong> means national system employee within the meaning of the Act but does not include an employee covered by the <em>Educational Services (Teachers) Award 2010</em></p><p><strong>employee organisation</strong> has the meaning given by section 12 of <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p><strong>employer</strong> means national system employer within the meaning of the Act</p><p><strong>enterprise</strong> has the meaning given by section 12 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p><strong>enterprise award-based instrument</strong> has the meaning in the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>exempt public sector superannuation scheme</strong> has the meaning given by the <em>Superannuation Industry (Supervision) Act 1993</em> (Cth)</p><p><strong>MySuper product</strong> has the meaning given by the <em>Superannuation Industry (Supervision) Act 1993</em> (Cth)</p><p><strong>long day care centre</strong> means a childcare establishment which usually provides services over a period of approximately eight hours or more each day for approximately 48 weeks or more during the year</p><p><strong>NES</strong> means the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">National Employment Standards</a> as contained in <a href="http://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">sections 59 to 131</a> of the <em>Fair Work Act 2009</em> (Cth)</p><p><strong>occasional care</strong> means a service that provides short-term childcare</p><p><strong>on-hire</strong> means the on-hire of an employee by their employer to a client, where such employee works under the general guidance and instruction of the client or a representative of the client</p><p><strong>out-of-school hours care</strong> means a program providing childcare and recreation before and/or after school hours and/or during school vacation periods</p><p><strong>preschool</strong> means a kindergarten, day school or nursery school and will include:</p><p>a. a full day care centre which means an establishment which does not operate on a sessional basis, but which usually operates during hours and terms which approximate those of a recognised school.</p><p>b. a sessional care centre which means an establishment which operates on the basis of morning and/or afternoon sessions and which usually operates during hours and terms which approximate those of a recognised school.</p><p><strong>regular casual employee</strong> has the meaning given by section 12 of the Act.</p><p><strong>school education weeks of the year</strong> means the school education weeks of the year as gazetted or recognised in the relevant State or Territory</p><p><strong>small business employer</strong> has the meaning given by section 23 of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><p><strong>standard rate</strong> means the minimum weekly rate for a Children&#39;s Services Employee Level 3.1 (Certificate III qualified) in <a href="/eba/ebas/childrens-services/wages/14-minimum-wages.html">clause 14</a>---Minimum wages</p><p><strong>transitional minimum wage instrument</strong> has the meaning in the <em>Fair Work (Transitional Provisions and Consequential Amendments) Act 2009</em> (Cth)</p><p><strong>unit</strong> means a group or class of children which does not at any one time exceed 25 children, but which need not necessarily consist of the same children at all times</p><p><strong>vacation care</strong> means a service that provides care for school age children during non‑term time</p><p><strong>workplace delegate</strong> has the meaning given by section 350C(1) of the <a href="http://www.legislation.gov.au/Series/C2009A00028" target="_blank" rel="noreferrer">Act</a>.</p><ol><li>Where this award refers to a condition of employment provided for in the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a>, the <a href="https://www.fwc.gov.au/documents/awards/resources/nes.pdf" target="_blank" rel="noreferrer">NES</a> definition applies.</li></ol><p>Plain language terms: glossary, meanings.</p>',41)])])}const g=n(o,[["render",s]]);export{d as __pageData,g as default};
